ther of Jimmu)}} |no |no |yes |- |{{ill|Sarutahiko Ōkami|en|Sarutahiko Ōkami|qid=Q3090037|lt=Shioshiji-no-Okina, Sarutahiko-no-Mikoto|1=Sarutahiko Ōkami}} |no |no |yes |- |{{ill|Emperor Tenji|en|Emperor Tenji|qid=Q314802|lt=Emperor Tenji|1=Emperor Tenji}} |no |no |yes |- |Ōmiya-hime |no |no |yes |- | | | | |}
